from vex import verify

@verify(
    checks=[
        "idempotency_check",
        "rollback_capability",
        "state_consistency"
    ],
    idempotency_field="idempotency_key"
)
def idempotent_workflow(customer_id: str, amount: float):
    tx_id = tx_manager.create_transaction(customer_id)

    try:
        result = workflow_agent.run(
            f"Payment workflow. TX: {tx_id}, Amount: ${amount}"
        )
        # Vex verifies final state consistency
        return result
    except Exception:
        # Vex ensures rollback verification
        tx_manager.rollback(tx_id)
        raise

# Prevents duplicate processing
idempotent_result = idempotent_workflow("customer123", 1500.00)
